%[DOCS AUTOGENERATED]
function [figs,results_tab] = experiments_plot(b,X_ins,ratios,LCOE,cost,power,failed,failed_mat,pareto_results_struct)
% Function experiments_plot
%
% :param b: Design variable bounds struct
% :param X_ins: X_ins
% :param ratios: ratios
% :param LCOE: Levelized cost of energy ($/kWh)
% :param cost: cost
% :param power: power
% :param failed: Indices or names of violated constraints
% :param failed_mat: failed_mat
% :param pareto_results_struct: pareto_results_struct
% :returns: Figure handles
% :returns: results_tab
%EXPERIMENTS_PLOT Post processing for design space exploration

    if nargin < 9
        pareto_results_struct = [];
    end
    idx_infeasible = ~cell2mat(cellfun(@isempty,failed_mat,'UniformOutput',false));

    % create table for display	
    results_tab = array2table(X_ins, 'VariableNames', b.var_names(1:end-1));	
    LCOE = LCOE';
    cost = cost';
    power = power';
    results_tab = addvars(results_tab, round(LCOE(LCOE~=Inf),2), round(cost(cost~=Inf),1), failed, ...
                    'NewVariableNames', {'LCOE ($/kWh)','c_v (%)','Failed Constraints'});
    
    % plot pareto curve for comparison, if pareto results exist
    if ~isempty(pareto_results_struct)
        pareto_figs = pareto_curve_heuristics(pareto_results_struct);
        pareto_fig_num = pareto_figs(3).Number;
        fig1 = figure(pareto_fig_num);
        plot(power/1e3, cost, '*--')
        
        title('Design of Experiments Pareto Front')
        l = legend(b.var_names_pretty);
        improvePlot
        l.Location = 'bestoutside';
    else
        fig1 = gobjects(1,1);
    end
    %% sensitivities plot
    
    LCOE(1,:) = LCOE(1,1); % fill in nominal LCOE results for each DV where it wasn't repeatedly tested
    cost(1,:) = cost(1,1);

    [ratios_sorted,idx] = sort(ratios);
    sorted_LCOE = LCOE(idx,:).';
    sorted_cost = cost(idx,:).';
    sorted_idx_infeasible = idx_infeasible(:,idx);
    
    fig2 = figure;
    t = tiledlayout(2,1);
    t.TileSpacing = 'compact';
    
    % LCOE subplot
    ax1 = nexttile(1);
    cols = {'r:','r--','r-','r-.','r.',...       % bulk dims
            'b:','b--',...                       % PTO
            'g:','g--','g-','g-.','g.'};  % structural
    yline(LCOE(1,1),'LineWidth',2,'Color','k','HandleVisibility','off')
    hold on
    for i = 1:size(cols,2)
        style = cols{i};
        color = style(1);
        sorted_idx_infeasible_i = sorted_idx_infeasible(i,:);
        
        plot(ratios_sorted,sorted_LCOE(i,:),style) % both feasible and infeasible
        plot(ratios_sorted(~sorted_idx_infeasible_i),sorted_LCOE(i,~sorted_idx_infeasible_i),'ok','HandleVisibility','off') % o over feasible
        hold on
        plot(ratios_sorted(sorted_idx_infeasible_i), sorted_LCOE(i, sorted_idx_infeasible_i),'xk','HandleVisibility','off') % x over infeasible
    end
    
    ylab1 = ylabel('LCOE ($/kWh)');
    x_range = [1/3 3];
    axis(ax1,[x_range 0.95*min(LCOE(:)) 1.1])
    l = legend(b.var_names_pretty{1:end-1});
    l.Location = 'northeastoutside';
    grid on
    hold off
    
    % cost subplot
    ax2 = nexttile(2);
    yline(cost(1,1),'LineWidth',2,'Color','k')
    hold on
    for i=1:size(cols,2)
        sorted_idx_infeasible_i = sorted_idx_infeasible(i,:);
        plot(ratios_sorted,sorted_cost(i,:),cols{i}) % both feasible and infeasible
        plot(ratios_sorted(~sorted_idx_infeasible_i),sorted_cost(i,~sorted_idx_infeasible_i),'ok','HandleVisibility','off') % o over feasible
        plot(ratios_sorted(sorted_idx_infeasible_i),sorted_cost(i,sorted_idx_infeasible_i),'xk','HandleVisibility','off') % x over infeasible
    end
    
    ylab2=ylabel('Structural & PTO Cost ($M)');
    grid on
    
    % shared plot
    title(t,'Design of Experiments Results','FontWeight','bold','FontSize',20)
    grid on
    linkaxes([ax1,ax2],'x');
    xlabel('Design Variable Ratio (-)')
    xticklabels(ax1,{})
    xticks(ax2,xticks(ax1))
    improvePlot
    ylab1.FontSize=16.5;
    ylab2.FontSize=16.5;
    xlim(x_range)
    fig2.Position(3:4) = [600  666]; % make taller
    
    figs = [fig1,fig2];
end

